#include <stdio.h>
#define VELICINA 3

int main() {
    int matrica[VELICINA][VELICINA];
    int i, j;

    /* unos matrice */
    for (i = 0; i < VELICINA; i++) {
        for (j = 0; j < VELICINA; j++) {
            printf("Unesite element [%d][%d]: \n", i, j);
            scanf("%d", &matrica[i][j]);
        }
    }

    /* ispis elemenata na glavnoj dijagonali */
    printf("\nElementi na glavnoj dijagonali: ");
    for (i = 0; i < VELICINA; i++) {
        printf("%d ", matrica[i][i]);
    }

    return 0;
}
